                                            {header:'Valor (R$)', key:'valor', render: item => <span className={`font-black whitespace-nowrap text-base ${item.tipo === 'entrada' ? 'text-emerald-600' : 'text-rose-600'}`}>R$ {parseFloat(item.valor).toFixed(2)}</span>}
